class Solution:
    def removeBoxes(self, boxes):
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(100000)
        n = len(boxes)
        # independent top-down formulation distinct from the bottom-up table version
        @lru_cache(maxsize=None)
        def solve(i, j, k):
            if i > j:
                return 0
            # collapse leading equal boxes into the attached count
            ii, kk = i, k
            while ii + 1 <= j and boxes[ii + 1] == boxes[ii]:
                ii += 1
                kk += 1
            best = (kk + 1) * (kk + 1) + solve(ii + 1, j, 0)
            for m in range(ii + 1, j + 1):
                if boxes[m] == boxes[ii]:
                    best = max(best, solve(ii + 1, m - 1, 0) + solve(m, j, kk + 1))
            return best
        return solve(0, n - 1, 0)

