var removeBoxes = function(boxes) {
    const n = boxes.length;
    const memo = new Map();
    function dp(i, j, k) {
        if (i > j) return 0;
        const key = i + ',' + j + ',' + k;
        if (memo.has(key)) return memo.get(key);
        let best = (k + 1) * (k + 1) + dp(i + 1, j, 0);
        for (let m = i + 1; m <= j; m++) {
            if (boxes[m] === boxes[i]) {
                best = Math.max(best, dp(i + 1, m - 1, 0) + dp(m, j, k + 1));
            }
        }
        memo.set(key, best);
        return best;
    }
    return dp(0, n - 1, 0);
};
